        get
        {
            var user = GetAuthenticatedUser();
            return user.FindFirstValue(ClaimTypes.Email)
                ?? user.FindFirstValue(JwtRegisteredClaimNames.Email)
                ?? throw new InvalidOperationException("User is not authenticated.");
        }
    }

